insert  into `p_company`(`id`,`company_name`,`company_name_th`,`company_name_en`,`country`,`company_type`,`website`,`address`,`city`,`province`,`phone`,`whatsapp`,`email`,`main_products`,`main_market`,`import_ability`,`purchase_scale`,`china_supplier_acceptance`,`oem_aftermarket_match`,`export_ability`,`customization_match`,`quality_requirement`,`price_sensitivity`,`delivery_requirement`,`accept_china_factory`,`customization_ability`,`after_sales_requirement`,`supply_chain_pain_points`,`recommended_products`,`recommended_channels`,`first_email_strategy`,`follow_up_immediately`,`added_to_crm`,`manual_follow_up`,`remarketing`,`next_follow_up_time`,`development_email`,`email_subject`,`development_email_template`,`lead_score`,`lead_grade`,`score_details`,`is_auto_parts_core`,`is_importer_distributor`,`has_oem_cooperation`,`employee_count`,`website_completeness`,`source`,`source_url`,`raw_data`,`status`,`is_duplicate`,`duplicate_of`,`assigned_to`,`created_at`,`updated_at`,`last_contacted_at`,`core_contact`,`annual_revenue_usd`,`purchase_potential`,`development_priority`,`notes`) values (412,'SunIntertrade Co., Ltd.',NULL,NULL,'Thailand','Importer','https://www.sunintertrade.com','34/9 Moo 2, Phetkrasem Rd., Nongkhangploo, Nong Khaem, Bangkok 10160',NULL,NULL,'+6628107788',NULL,'jr.sun@outlook.com','皮卡/乘用车/商用车/农机全品类配件，5000+ SKU','泰国、东南亚、中东、非洲',23,24,18,14,9,4,'JIS/BS标准；OEM匹配度高；UV耐候；高温高湿适应','中','快','是','强','无缺陷政策；质量追溯；退换货；技术指导','日本原厂成本高；需要更多替代供应商；多车型SKU管理','后视镜总成、车身外饰件、格栅、雾灯罩','Email + 混合','30年老牌批发商，5000+SKU，中国工厂可降30%成本',NULL,NULL,NULL,NULL,NULL,'Dear SunIntertrade Co., Ltd. Team,\n\nGreetings from 佛山市鼎和盛汽车配件有限公司! As a professional automotive parts importer, you understand the importance of reliable suppliers and smooth logistics. We\'d like to introduce ourselves as your direct sourcing partner from China.\n\nWe specialize in:\n• 后视镜总成、车身外饰件、格栅、雾灯罩\n\n\nWe\'ve analyzed the supply chain landscape and understand 日本原厂成本高；需要更多替代供应商；多车型SKU管理. Our solutions are specifically designed to address these challenges effectively.\n\n\nOur Import-Friendly Services:\n? Direct factory pricing - eliminate middlemen\n? Full container load (FCL) and less than container load (LCL) options\n? Complete documentation support: commercial invoice, packing list, CO, CIQ\n✅ Quality inspection before shipment\n\n\n\n\n\n\n✅ Dedicated account manager for your imports\n\n✅ Comprehensive after-sales support including product training and technical assistance\n\n\n\n\nWith your focus on 泰国、东南亚、中东、非洲, our products are well-positioned to meet local market demands.\n\n\n\n\n30年老牌批发商，5000+SKU，中国工厂可降30%成本\n\n\nWould you be interested in receiving our import pricing list and discussing how we can streamline your China sourcing?\n\nPlease visit our website: https://www.carparts-land.com/\n\nBest regards,\nLeo Leung\nExport Sales Manager\n佛山市鼎和盛汽车配件有限公司\n? +86 180-7886-5445\n? market@carparts-land.com\n? https://www.carparts-land.com/\n? Foshan City, Guangdong Province, China\n','Direct China Pickup truck/Passenger... Sourcing - Foshan Dinghesheng Auto Parts Co., Ltd | Import Simplified','Dear SunIntertrade Co., Ltd. Team,\n\nGreetings from Foshan Dinghesheng Auto Parts Co., Ltd! As a professional automotive parts importer, you understand the importance of reliable suppliers and smooth logistics. We\'d like to introduce ourselves as your direct sourcing partner from China.\n\nWe specialize in:\n• Mirrorassemblies、Exterior body parts、Grilles、Fog lamp covers\n\n\nWhy choose us:\n✅ Direct factory pricing - no middlemen\n✅ Full import documentation support\n✅ Door-to-door logistics options\n\n\n\n\n\n\n\n\n\n✅ Low MOQ for trial orders\n✅ Quality control inspections before shipment\n✅ English-speaking support team\n\n\n✅ Comprehensive after-sales support including product training and technical assistance\n\n\n\n\nWe\'ve analyzed the supply chain landscape and understand Japanese OEMCostHigh；need moreAlternative suppliers；Multi-modelSKU management. Our solutions are specifically designed to address these challenges effectively.\n\n\n\nWith your focus on Thailand、Southeast Asia、Middle East、Africa, our products are well-positioned to meet local market demands.\n\n\n\n\n\n30-year establishedWholesaler，5000+SKU，Chinafactorycan reduce30%Cost\n\n\nLet us simplify your China sourcing. Would you be interested in receiving our product catalog and competitive pricing?\n\nVisit us: https://www.carparts-land.com/\n\nLeo Leung\nExport Sales Manager\nFoshan Dinghesheng Auto Parts Co., Ltd\n? +86 180-7886-5445\n? market@carparts-land.com\n? https://www.carparts-land.com/\n? Foshan City, Guangdong Province, China',92,'A',NULL,1,1,0,NULL,0,'Industry_Directory','泰国汽车配件客户分析报告.txt; 泰国汽车配件客户分析报告.txt; 泰国汽车配件客户开发清单_完整版.xlsx',NULL,'New',0,NULL,NULL,'2026-06-26 19:00:26','2026-06-26 20:18:44',NULL,'',NULL,NULL,NULL,NULL);
