insert  into `p_email_record`(`id`,`campaign_id`,`company_id`,`contact_id`,`template_id`,`in_reply_to_email_id`,`recipient_email`,`subject`,`content`,`status`,`sent_at`,`opened_at`,`replied_at`,`reply_content`,`error_message`,`tracking_id`,`message_id`,`created_at`) values (9,NULL,795,NULL,NULL,NULL,'liangky1985@gmail.com','Competitive Genuine BMW automotive parts... Supply - Foshan Dinghesheng Auto Parts Co., Ltd | Boost Your Margins','Dear BMW Thailand Parts Division Team,\n\nHope this email finds you well! My name is Leo Leung from 佛山市鼎和盛汽车配件有限公司, a leading Chinese auto parts factory specializing in exterior components for pickup trucks, SUVs, and passenger vehicles.\n\nWith your strong presence in Genuine BMW automotive parts distribution., we believe we can be your ideal supplier for:\n• Mirror assemblies, pillar trims, roof racks, grilles, fog lamp covers\n\n\n\nWhy partner with us:\n✅ OEM-grade quality at competitive prices\n✅ MOQ as low as 50 sets per model\n\n\n✅ Full export support: packaging, documentation, logistics\n✅ Custom branding and packaging available\n✅ Sample support for quality verification\n\n\n\n\n\n\nAs a distributor focused on Genuine BMW automotive parts distribution., adding our cost-effective exterior parts can significantly boost your margins while maintaining quality standards for your customers.\n\n\n\nWe\'d love to send you our product catalog and sample pricing. Would you be available for a brief call next week to discuss your specific needs?\n\nVisit us: https://www.carparts-land.com/\n\nBest regards,\nLeo Leung\nExport Sales Manager\n佛山市鼎和盛汽车配件有限公司\n? +86 180-7886-5445\n? market@carparts-land.com\n? https://www.carparts-land.com/\n? Foshan City, Guangdong Province, China\n','Sent','2026-06-26 23:00:51',NULL,NULL,NULL,NULL,'5b75f8d8-b7be-4877-b6e0-db55440761d6',NULL,'2026-06-26 23:00:49');
