insert  into `p_inbound_email`(`id`,`company_id`,`contact_id`,`from_email`,`from_name`,`is_replied`,`to_email`,`subject`,`content`,`message_id`,`in_reply_to`,`is_read`,`is_starred`,`attachments`,`created_at`,`priority`,`config_type`) values (10,NULL,NULL,'liangky1985@gmail.com','梁滴',1,'market@carparts-land.com','Re: Competitive Genuine BMW automotive parts... Supply - Foshan Dinghesheng Auto Parts Co., Ltd | Boost Your Margins','<div dir=\"auto\">its my pleasture</div><br><div class=\"gmail_quote gmail_quote_container\"><div dir=\"ltr\" class=\"gmail_attr\">On Fri, Jun 26, 2026, 23:00  &lt;<a href=\"mailto:market@carparts-land.com\">market@carparts-land.com</a>&gt; wrote:<br></div><blockquote class=\"gmail_quote\" style=\"margin:0 0 0 .8ex;border-left:1px #ccc solid;padding-left:1ex\">Dear BMW Thailand Parts Division Team,<br>\r\n<br>\r\nHope this email finds you well! My name is Leo Leung from 佛山市鼎和盛汽车配件有限公司, a leading Chinese auto parts factory specializing in exterior components for pickup trucks, SUVs, and passenger vehicles.<br>\r\n<br>\r\nWith your strong presence in Genuine BMW automotive parts distribution., we believe we can be your ideal supplier for:<br>\r\n• Mirror assemblies, pillar trims, roof racks, grilles, fog lamp covers<br>\r\n<br>\r\n<br>\r\n<br>\r\nWhy partner with us:<br>\r\n✅ OEM-grade quality at competitive prices<br>\r\n✅ MOQ as low as 50 sets per model<br>\r\n<br>\r\n<br>\r\n✅ Full export support: packaging, documentation, logistics<br>\r\n✅ Custom branding and packaging available<br>\r\n✅ Sample support for quality verification<br>\r\n<br>\r\n<br>\r\n<br>\r\n<br>\r\n<br>\r\n<br>\r\nAs a distributor focused on Genuine BMW automotive parts distribution., adding our cost-effective exterior parts can significantly boost your margins while maintaining quality standards for your customers.<br>\r\n<br>\r\n<br>\r\n<br>\r\nWe&#39;d love to send you our product catalog and sample pricing. Would you be available for a brief call next week to discuss your specific needs?<br>\r\n<br>\r\nVisit us: <a href=\"https://www.carparts-land.com/\" rel=\"noreferrer noreferrer\" target=\"_blank\">https://www.carparts-land.com/</a><br>\r\n<br>\r\nBest regards,<br>\r\nLeo Leung<br>\r\nExport Sales Manager<br>\r\n佛山市鼎和盛汽车配件有限公司<br>\r\n? +86 180-7886-5445<br>\r\n? <a href=\"mailto:market@carparts-land.com\" target=\"_blank\" rel=\"noreferrer\">market@carparts-land.com</a><br>\r\n? <a href=\"https://www.carparts-land.com/\" rel=\"noreferrer noreferrer\" target=\"_blank\">https://www.carparts-land.com/</a><br>\r\n? Foshan City, Guangdong Province, China<br>\r\n</blockquote></div>\r\n','<CACj7kV7vmU7T73X-GVXqhg5O6vtWwc1+wRry0dweKcNsmQK=Qg@mail.gmail.com>','<1299964455.0.1782486050519@dennis>',1,0,NULL,'2026-06-26 23:04:10',NULL,NULL);
