/*Table structure for table `p_company` */

DROP TABLE IF EXISTS `p_company`;

CREATE TABLE `p_company` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `company_name` varchar(255) NOT NULL COMMENT '公司名称',
  `company_name_th` varchar(255) DEFAULT NULL COMMENT '公司名称(泰文)',
  `company_name_en` varchar(255) DEFAULT NULL COMMENT '公司名称(英文)',
  `country` varchar(50) DEFAULT 'Thailand' COMMENT '国家',
  `company_type` enum('Distributor','Importer','OEM','Retailer','Manufacturer','Other') DEFAULT NULL COMMENT '公司类型',
  `website` varchar(255) DEFAULT NULL COMMENT '官网URL',
  `address` varchar(500) DEFAULT NULL COMMENT '详细地址',
  `city` varchar(100) DEFAULT NULL COMMENT '城市',
  `province` varchar(100) DEFAULT NULL COMMENT '省份',
  `phone` varchar(50) DEFAULT NULL COMMENT '电话',
  `whatsapp` varchar(50) DEFAULT NULL COMMENT 'WhatsApp号码',
  `email` varchar(100) DEFAULT NULL COMMENT '公司邮箱',
  `main_products` varchar(500) DEFAULT NULL COMMENT '主营产品',
  `main_market` varchar(200) DEFAULT NULL COMMENT '主要销售市场',
  `import_ability` int(11) DEFAULT NULL COMMENT '进口能力(0-25)',
  `purchase_scale` int(11) DEFAULT NULL COMMENT '采购规模(0-25)',
  `china_supplier_acceptance` int(11) DEFAULT NULL COMMENT '中国供应商接受度(0-20)',
  `oem_aftermarket_match` int(11) DEFAULT NULL COMMENT 'OEM/Aftermarket匹配度(0-15)',
  `export_ability` int(11) DEFAULT NULL COMMENT '出口能力(0-10)',
  `customization_match` int(11) DEFAULT NULL COMMENT '定制需求匹配度(0-5)',
  `quality_requirement` varchar(100) DEFAULT NULL COMMENT '质量要求',
  `price_sensitivity` varchar(100) DEFAULT NULL COMMENT '价格敏感度',
  `delivery_requirement` varchar(100) DEFAULT NULL COMMENT '交期要求',
  `accept_china_factory` varchar(50) DEFAULT NULL COMMENT '接受中国工厂',
  `customization_ability` varchar(200) DEFAULT NULL COMMENT '定制能力需求',
  `after_sales_requirement` varchar(200) DEFAULT NULL COMMENT '售后要求',
  `supply_chain_pain_points` text COMMENT '当前供应链痛点',
  `recommended_products` varchar(500) DEFAULT NULL COMMENT '推荐切入产品',
  `recommended_channels` varchar(200) DEFAULT NULL COMMENT '推荐渠道',
  `first_email_strategy` text COMMENT '首封开发信策略',
  `follow_up_immediately` varchar(50) DEFAULT NULL COMMENT '是否立即跟进',
  `added_to_crm` varchar(50) DEFAULT NULL COMMENT '加入CRM',
  `manual_follow_up` varchar(50) DEFAULT NULL COMMENT '人工跟进',
  `remarketing` varchar(50) DEFAULT NULL COMMENT '再营销',
  `next_follow_up_time` datetime DEFAULT NULL COMMENT '下次跟进时间',
  `development_email` text COMMENT '开发信(英文)',
  `email_subject` varchar(255) DEFAULT NULL,
  `development_email_template` text,
  `lead_score` int(11) DEFAULT '0' COMMENT '客户评分(0-100)',
  `lead_grade` enum('S','A','B','C') DEFAULT 'C' COMMENT '客户等级',
  `score_details` json DEFAULT NULL COMMENT '评分明细JSON',
  `is_auto_parts_core` tinyint(1) DEFAULT '0' COMMENT '是否汽配核心业务',
  `is_importer_distributor` tinyint(1) DEFAULT '0' COMMENT '是否进口/分销商',
  `has_oem_cooperation` tinyint(1) DEFAULT '0' COMMENT '是否有OEM合作',
  `employee_count` varchar(50) DEFAULT NULL COMMENT '员工规模',
  `website_completeness` int(11) DEFAULT '0' COMMENT '官网完整度(0-100)',
  `source` enum('Google','LinkedIn','B2B_Platform','Industry_Directory','Manual','API') DEFAULT NULL COMMENT '数据来源',
  `source_url` varchar(500) DEFAULT NULL COMMENT '来源URL',
  `raw_data` json DEFAULT NULL COMMENT '原始数据JSON',
  `status` enum('New','Contacted','Replied','Quoted','Negotiation','Sample_Sent','Won','Lost','Invalid') DEFAULT 'New' COMMENT '客户状态',
  `is_duplicate` tinyint(1) DEFAULT '0' COMMENT '是否重复',
  `duplicate_of` bigint(20) DEFAULT NULL COMMENT '重复指向的公司ID',
  `assigned_to` bigint(20) DEFAULT NULL COMMENT '分配给的销售人员ID',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `last_contacted_at` datetime DEFAULT NULL COMMENT '最后联系时间',
  `core_contact` varchar(200) DEFAULT NULL COMMENT '核心联系人',
  `annual_revenue_usd` decimal(15,2) DEFAULT NULL COMMENT '年营收(USD)',
  `purchase_potential` varchar(50) DEFAULT NULL COMMENT '采购潜力',
  `development_priority` varchar(50) DEFAULT NULL COMMENT '开发优先级',
  `notes` varchar(500) DEFAULT NULL COMMENT '备注信息',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_company_name_country` (`company_name`,`country`),
  KEY `idx_company_name` (`company_name`),
  KEY `idx_lead_grade` (`lead_grade`),
  KEY `idx_status` (`status`),
  KEY `idx_source` (`source`),
  KEY `idx_country_city` (`country`,`city`)
) ENGINE=InnoDB AUTO_INCREMENT=814 DEFAULT CHARSET=utf8mb4 COMMENT='客户公司表';

