  `is_importer_distributor` tinyint(1) DEFAULT '0' COMMENT '是否进口/分销商',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `confirmed_at` datetime DEFAULT NULL COMMENT '确认时间',
