  KEY `idx_lead_grade` (`lead_grade`),
  CONSTRAINT `p_crawler_result_ibfk_1` FOREIGN KEY (`task_id`) REFERENCES `p_crawler_task` (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='爬虫抓取结果表(待确认)';

