/*Table structure for table `p_crawler_task` */

DROP TABLE IF EXISTS `p_crawler_task`;

CREATE TABLE `p_crawler_task` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT,
  `task_name` varchar(200) NOT NULL COMMENT '任务名称',
  `source_type` enum('Google_Search','Google_Maps','LinkedIn','B2B_Platform','Industry_Directory') DEFAULT NULL COMMENT '数据源',
  `keywords` json DEFAULT NULL COMMENT '搜索关键词列表',
  `target_country` varchar(50) DEFAULT 'Thailand' COMMENT '目标国家',
  `target_city` varchar(100) DEFAULT NULL COMMENT '目标城市',
  `filters` json DEFAULT NULL COMMENT '过滤条件',
  `status` enum('Pending','Running','Completed','Failed','Paused') DEFAULT 'Pending' COMMENT '状态',
  `progress` int(11) DEFAULT '0' COMMENT '进度(0-100)',
  `total_found` int(11) DEFAULT '0' COMMENT '发现总数',
  `new_companies` int(11) DEFAULT '0' COMMENT '新增公司数',
  `duplicates` int(11) DEFAULT '0' COMMENT '重复数',
  `errors` int(11) DEFAULT '0' COMMENT '错误数',
