/*Table structure for table `p_daily_stats` */

DROP TABLE IF EXISTS `p_daily_stats`;

CREATE TABLE `p_daily_stats` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT,
  `stat_date` date NOT NULL COMMENT '统计日期',
  `new_leads` int(11) DEFAULT '0' COMMENT '新增线索',
  `leads_by_source` json DEFAULT NULL COMMENT '按来源分类',
  `leads_by_grade` json DEFAULT NULL COMMENT '按等级分类',
  `emails_sent` int(11) DEFAULT '0' COMMENT '邮件发送数',
  `emails_opened` int(11) DEFAULT '0' COMMENT '邮件打开数',
