  `whatsapp_sent` int(11) DEFAULT '0' COMMENT 'WA发送数',
  `whatsapp_replied` int(11) DEFAULT '0' COMMENT 'WA回复数',
  `linkedin_actions` int(11) DEFAULT '0' COMMENT 'LinkedIn操作数',
  `new_replies` int(11) DEFAULT '0' COMMENT '新增回复',
  `new_quotations` int(11) DEFAULT '0' COMMENT '新增报价',
  `new_samples` int(11) DEFAULT '0' COMMENT '新增样品',
  `deals_won` int(11) DEFAULT '0' COMMENT '成交数',
