CREATE TABLE `p_email_record` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT,
  `campaign_id` bigint(20) DEFAULT NULL COMMENT '活动ID',
  `company_id` bigint(20) DEFAULT NULL COMMENT '公司ID',
