  KEY `idx_is_read` (`is_read`),
  KEY `idx_is_starred` (`is_starred`),
  KEY `idx_created_at` (`created_at`),
  CONSTRAINT `p_inbound_email_ibfk_1` FOREIGN KEY (`company_id`) REFERENCES `p_company` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=11 DEFAULT CHARSET=utf8mb4 COMMENT='收件箱表';

