/*Table structure for table `p_linkedin_record` */

DROP TABLE IF EXISTS `p_linkedin_record`;

CREATE TABLE `p_linkedin_record` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT,
  `company_id` bigint(20) NOT NULL,
  `contact_id` bigint(20) DEFAULT NULL,
  `linkedin_profile_url` varchar(500) DEFAULT NULL COMMENT 'LinkedIn主页',
  `linkedin_id` varchar(100) DEFAULT NULL COMMENT 'LinkedIn用户ID',
  `action_type` enum('View_Profile','Connect','Message','Follow','Engage_Post') DEFAULT NULL COMMENT '操作类型',
  `status` enum('Pending','Success','Failed','Ignored','Blocked') DEFAULT 'Pending' COMMENT '状态',
  `message_content` text COMMENT '消息内容',
  `response_content` text COMMENT '回复内容',
  `scheduled_at` datetime DEFAULT NULL COMMENT '计划执行时间',
  `executed_at` datetime DEFAULT NULL COMMENT '执行时间',
  `error_message` text,
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_company_id` (`company_id`),
  KEY `idx_action_type` (`action_type`),
  KEY `idx_status` (`status`),
  CONSTRAINT `p_linkedin_record_ibfk_1` FOREIGN KEY (`company_id`) REFERENCES `p_company` (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='LinkedIn互动记录表';

/*Data for the table `p_linkedin_record` */

/*Table structure for table `p_product` */

DROP TABLE IF EXISTS `p_product`;

CREATE TABLE `p_product` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `product_name` varchar(200) NOT NULL COMMENT '产品名称',
  `product_code` varchar(50) DEFAULT NULL COMMENT '产品编码',
  `category` varchar(50) DEFAULT NULL COMMENT '产品类别',
  `brand` varchar(100) DEFAULT NULL COMMENT '品牌',
  `specification` varchar(500) DEFAULT NULL COMMENT '规格',
  `image_url` varchar(100) DEFAULT NULL,
  `unit_price` decimal(10,2) DEFAULT NULL COMMENT '单价(USD)',
  `stock` int(11) DEFAULT '0' COMMENT '库存',
  `description` text COMMENT '产品描述',
  `status` varchar(20) DEFAULT 'active' COMMENT '状态:active-在售,inactive-下架',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `model` varchar(100) DEFAULT NULL COMMENT '型号',
  `dimensions` varchar(100) DEFAULT NULL COMMENT '产品尺寸',
  `pkg_length` int(11) DEFAULT NULL COMMENT '包装长(mm)',
  `pkg_width` int(11) DEFAULT NULL COMMENT '包装宽(mm)',
  `pkg_height` int(11) DEFAULT NULL COMMENT '包装高(mm)',
  `qty_per_pkg` int(11) DEFAULT NULL COMMENT '每箱数量',
  `car_model` varchar(200) DEFAULT NULL COMMENT '适用车型',
  `production_date` date DEFAULT NULL COMMENT '量产日期',
  `weight` decimal(10,2) DEFAULT NULL COMMENT '重量(g)',
  PRIMARY KEY (`id`),
  KEY `idx_product_name` (`product_name`),
  KEY `idx_category` (`category`),
  KEY `idx_status` (`status`)
) ENGINE=InnoDB AUTO_INCREMENT=233 DEFAULT CHARSET=utf8mb4 COMMENT='产品表';

/*Data for the table `p_product` */


/*Table structure for table `p_product_interest` */

DROP TABLE IF EXISTS `p_product_interest`;

CREATE TABLE `p_product_interest` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT,
  `company_id` bigint(20) NOT NULL,
  `product_category` enum('Exterior','Interior','Structural','Electrical','Engine','Suspension','Brake','Lighting','Mirror','Grille','Bumper','Other') DEFAULT NULL COMMENT '产品类别',
  `product_name` varchar(200) DEFAULT NULL COMMENT '具体产品名称',
  `interest_level` enum('High','Medium','Low') DEFAULT 'Medium' COMMENT '兴趣程度',
  `source` varchar(200) DEFAULT NULL COMMENT '来源(从什么渠道得知)',
  `notes` text,
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_company_id` (`company_id`),
  KEY `idx_product_category` (`product_category`),
  CONSTRAINT `p_product_interest_ibfk_1` FOREIGN KEY (`company_id`) REFERENCES `p_company` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='产品兴趣表';

/*Data for the table `p_product_interest` */

/*Table structure for table `p_quotation` */

DROP TABLE IF EXISTS `p_quotation`;

CREATE TABLE `p_quotation` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT,
  `company_id` bigint(20) NOT NULL,
  `contact_id` bigint(20) DEFAULT NULL,
  `quotation_no` varchar(50) NOT NULL COMMENT '报价单号',
  `product_name` varchar(200) DEFAULT NULL COMMENT '产品名称',
  `product_description` text COMMENT '产品描述',
  `quantity` int(11) DEFAULT NULL COMMENT '数量',
  `unit_price` decimal(10,2) DEFAULT NULL COMMENT '单价(USD)',
  `total_amount` decimal(12,2) DEFAULT NULL COMMENT '总金额',
  `currency` varchar(10) DEFAULT 'USD' COMMENT '货币',
  `valid_until` date DEFAULT NULL COMMENT '有效期至',
  `terms` text COMMENT '条款',
  `notes` text COMMENT '备注',
  `status` enum('Draft','Sent','Viewed','Negotiating','Accepted','Rejected','Expired') DEFAULT 'Draft' COMMENT '状态',
  `sent_at` datetime DEFAULT NULL COMMENT '发送时间',
  `viewed_at` datetime DEFAULT NULL COMMENT '查看时间',
  `accepted_at` datetime DEFAULT NULL COMMENT '接受时间',
  `attachments` json DEFAULT NULL COMMENT '附件(报价单PDF等)',
  `created_by` bigint(20) DEFAULT NULL,
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `quotation_no` (`quotation_no`),
  KEY `idx_company_id` (`company_id`),
  KEY `idx_status` (`status`),
  KEY `idx_quotation_no` (`quotation_no`),
  CONSTRAINT `p_quotation_ibfk_1` FOREIGN KEY (`company_id`) REFERENCES `p_company` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COMMENT='报价单表';

/*Data for the table `p_quotation` */


/*Table structure for table `p_quotation_item` */

DROP TABLE IF EXISTS `p_quotation_item`;

CREATE TABLE `p_quotation_item` (
