/*Table structure for table `p_task` */

DROP TABLE IF EXISTS `p_task`;

CREATE TABLE `p_task` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT,
  `company_id` bigint(20) DEFAULT NULL,
  `contact_id` bigint(20) DEFAULT NULL,
  `assigned_to` bigint(20) NOT NULL COMMENT '负责人',
  `task_type` enum('Follow_Up','Send_Quote','Send_Sample','Call','Meeting','Other') DEFAULT NULL COMMENT '任务类型',
  `title` varchar(200) NOT NULL COMMENT '任务标题',
  `description` text COMMENT '任务描述',
  `priority` enum('High','Medium','Low') DEFAULT 'Medium' COMMENT '优先级',
  `status` enum('Pending','In_Progress','Completed','Cancelled') DEFAULT 'Pending' COMMENT '状态',
  `due_date` datetime DEFAULT NULL COMMENT '截止日期',
  `completed_at` datetime DEFAULT NULL COMMENT '完成时间',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `company_id` (`company_id`),
  KEY `idx_assigned_to` (`assigned_to`),
  KEY `idx_status` (`status`),
  KEY `idx_due_date` (`due_date`),
  CONSTRAINT `p_task_ibfk_1` FOREIGN KEY (`company_id`) REFERENCES `p_company` (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='任务表';

