/*Table structure for table `p_whatsapp_record` */

DROP TABLE IF EXISTS `p_whatsapp_record`;

CREATE TABLE `p_whatsapp_record` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT,
  `company_id` bigint(20) NOT NULL,
  `contact_id` bigint(20) DEFAULT NULL,
  `phone_number` varchar(50) NOT NULL COMMENT '收件人号码',
  `message_type` enum('Text','Image','Document','Video','Audio') DEFAULT 'Text' COMMENT '消息类型',
  `content` text COMMENT '文本内容',
  `media_url` varchar(500) DEFAULT NULL COMMENT '媒体文件URL',
  `direction` enum('Outbound','Inbound') DEFAULT NULL COMMENT '方向',
  `status` enum('Pending','Sent','Delivered','Read','Replied','Failed') DEFAULT 'Pending' COMMENT '状态',
  `sent_at` datetime DEFAULT NULL COMMENT '发送时间',
  `delivered_at` datetime DEFAULT NULL COMMENT '送达时间',
  `read_at` datetime DEFAULT NULL COMMENT '已读时间',
  `replied_at` datetime DEFAULT NULL COMMENT '回复时间',
  `reply_content` text COMMENT '回复内容',
  `error_message` text,
  `message_id` varchar(200) DEFAULT NULL COMMENT 'WA消息ID',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_company_id` (`company_id`),
  KEY `idx_phone_number` (`phone_number`),
  KEY `idx_status` (`status`),
  KEY `idx_sent_at` (`sent_at`),
  CONSTRAINT `p_whatsapp_record_ibfk_1` FOREIGN KEY (`company_id`) REFERENCES `p_company` (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='WhatsApp消息记录表';

